function updateBybitBadgeColors(){$('.tsg-bybit-leverage-badge-1').each(function(){const text=$(this).text().toLowerCase();$(this).removeClass('long short');if(text.includes('long')){$(this).addClass('long')}else if(text.includes('short')){$(this).addClass('short')}});$('.tsg-bybit-leverage-badge-2').each(function(){const text=$(this).text().toLowerCase();$(this).removeClass('long short');if(text.includes('long')){$(this).addClass('long')}else if(text.includes('short')){$(this).addClass('short')}});$('.tsg-bybit-roi-value-1, .tsg-bybit-roi-value-2').each(function(){const text=$(this).text();const roi=parseFloat(text.replace(/[+%]/g,''));$(this).removeClass('tsg-positive tsg-negative');if(roi>0){$(this).addClass('tsg-positive')}else{$(this).addClass('tsg-negative')}})}
