$(document).on('input','.tsg-bybit-battery-percentage-3',function(){updateBatteryIcon()});$(document).on('input','.tsg-ios-battery-text',function(){updateIOSBattery(this)});function updateIOSBattery(element){const $text=$(element);let percentageText=$text.text().replace(/[^0-9]/g,'');if(parseInt(percentageText)>100)percentageText="100";const percentage=parseInt(percentageText)||0;const clampedPercentage=Math.max(0,Math.min(100,percentage));$text.siblings('.tsg-ios-battery-fill').css('width',clampedPercentage+'%');const $fill=$text.siblings('.tsg-ios-battery-fill');if(clampedPercentage<=20){$fill.css('background-color','#FF3B30')}else{$fill.css('background-color','#FFFFFF')}}
