function initializeZoomControls(){let currentZoom=0.75;updateZoomDisplay(currentZoom);applyZoom(currentZoom);$('#tsg-zoom-out').on('click',function(){currentZoom=Math.max(0.25,currentZoom-0.25);updateZoomDisplay(currentZoom);applyZoom(currentZoom)});$('#tsg-zoom-in').on('click',function(){currentZoom=Math.min(2.0,currentZoom+0.25);updateZoomDisplay(currentZoom);applyZoom(currentZoom)});let isDragMode=!1;let isDragging=!1;let dragStartX=0;let dragStartY=0;let initialTransformX=0;let initialTransformY=0;$('#tsg-drag-toggle').on('click',function(){isDragMode=!isDragMode;$(this).toggleClass('active');if(isDragMode){$(this).attr('title','Disable Drag Mode');$('.tsg-container').css('cursor','grab')}else{$(this).attr('title','Enable Drag Mode');$('.tsg-container').css('cursor','default')}});$('.tsg-container').on('mousedown',function(e){if(!isDragMode)return;e.preventDefault();isDragging=!0;dragStartX=e.clientX;dragStartY=e.clientY;const currentTransform=$(this).css('transform');const matrix=new DOMMatrix(currentTransform);initialTransformX=matrix.m41;initialTransformY=matrix.m42;$(this).css('cursor','grabbing')});$(document).on('mousemove',function(e){if(!isDragging)return;const deltaX=e.clientX-dragStartX;const deltaY=e.clientY-dragStartY;const newX=initialTransformX+deltaX;const newY=initialTransformY+deltaY;$('.tsg-container').css('transform',`translate(${newX}px, ${newY}px) scale(${currentZoom})`)});$(document).on('mouseup',function(){if(!isDragging)return;isDragging=!1;if(isDragMode){$('.tsg-container').css('cursor','grab')}else{$('.tsg-container').css('cursor','default')}});const originalApplyZoom=applyZoom;applyZoom=function(zoom){originalApplyZoom(zoom);currentZoom=zoom}}
