function applyZoom(zoom){const container=$('.tsg-container');const activeLayout=container.find('.tsg-trading-history:visible');const currentTransform=container.css('transform');const matrix=new DOMMatrix(currentTransform);const currentTranslateX=matrix.m41;const currentTranslateY=matrix.m42;if(activeLayout.hasClass('binance-design-1-layout')||activeLayout.hasClass('binance-design-2-layout')||activeLayout.hasClass('binance-design-3-layout')||activeLayout.hasClass('binance-design-4-layout')||activeLayout.hasClass('binance-design-5-layout')){if(zoom===1.0){activeLayout.css('transform','scale(0.8)')}else{const finalScale=0.8*zoom;activeLayout.css('transform',`scale(${finalScale})`)}}else{if(zoom===1.0){container.removeClass('tsg-preview-scaled');container.css('transform',`translate(${currentTranslateX}px, ${currentTranslateY}px) scale(1)`)}else{container.addClass('tsg-preview-scaled');container.css('transform',`translate(${currentTranslateX}px, ${currentTranslateY}px) scale(${zoom})`)}}}
function generateRandomMoonXData(activeView,styleMode){console.log('generateRandomMoonXData called with:',activeView,styleMode);if(styleMode==='moon-x-design-1'){const tradingPairs=['SOL','BTC','ETH','LINK','ADA','DOT','AVAX','MATIC'];const randomPair=tradingPairs[Math.floor(Math.random()*tradingPairs.length)];const tradeTypes=['Long','Short'];const randomTradeType=tradeTypes[Math.floor(Math.random()*tradeTypes.length)];const randomLeverage=Math.floor(Math.random()*50)+1;const percentage=(Math.random()*100+10).toFixed(1);const usdtValue=(Math.random()*50+5).toFixed(1);const basePrice=Math.random()*200+50;const entryPrice=basePrice.toFixed(2);const exitPrice=(basePrice*(1+parseFloat(percentage)/100)).toFixed(2);const referralCode=Math.random().toString(36).substring(2,9).toUpperCase();const now=new Date();const randomMinutes=Math.floor(Math.random()*60);const randomDate=new Date(now.getTime()-randomMinutes*60000);const timestamp=randomDate.toLocaleString('en-GB',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit',second:'2-digit'}).replace(/,/g,'');activeView.find('.tsg-moon-x-tag').eq(0).text(randomTradeType);activeView.find('.tsg-moon-x-tag').eq(1).text(randomLeverage+'X');activeView.find('.tsg-moon-x-tag').eq(2).text(randomPair);activeView.find('.tsg-moon-x-percentage').text('+'+percentage+'%');activeView.find('.tsg-moon-x-usdt').text('(+'+usdtValue+' USDT)');activeView.find('.tsg-moon-x-price-value').eq(0).text(entryPrice);activeView.find('.tsg-moon-x-price-value').eq(1).text(exitPrice);activeView.find('.tsg-moon-x-referral-code').text(referralCode);activeView.find('.tsg-moon-x-timestamp-1').text('Time Stamp: '+timestamp)}else if(styleMode==='moon-x-design-2'){const tradingPairs=['LINK','BTC','ETH','SOL','ADA','DOT','AVAX','MATIC'];const randomPair=tradingPairs[Math.floor(Math.random()*tradingPairs.length)];const positionSize=(Math.random()*10000+1000).toFixed(8);const entryPrice=(Math.random()*50+10).toFixed(3);const markPrice=(parseFloat(entryPrice)*(1+Math.random()*0.1)).toFixed(3);const pnlPercentage=(Math.random()*100+10).toFixed(2);const pnlValue=(Math.random()*5000+500).toFixed(2);const margin=(Math.random()*10000+1000).toFixed(2);const liquidationPrice=(parseFloat(entryPrice)*0.9).toFixed(4);const positionId=Math.random().toString(16).substring(2,10)+'...'+Math.random().toString(16).substring(2,6);activeView.find('.tsg-moon-x-symbol').text(randomPair);activeView.find('.tsg-moon-x-position-id-value span').text(positionId);activeView.find('.tsg-moon-x-metric-value').eq(0).text(positionSize);activeView.find('.tsg-moon-x-metric-value').eq(1).text('$'+entryPrice);activeView.find('.tsg-moon-x-metric-value.tsg-moon-x-positive').text('+$'+pnlValue+' (+'+pnlPercentage+'%)');activeView.find('.tsg-moon-x-metric-value').eq(3).text('$'+margin);activeView.find('.tsg-moon-x-metric-value').eq(4).text('$'+markPrice);activeView.find('.tsg-moon-x-metric-value').eq(5).text('$'+liquidationPrice)}}
